-- Seed Yingoh NCLEX question bank, part 5.
-- Inserts only prompts that do not already exist, so it is safe to rerun.

insert into public.questions (
  topic,
  question_type,
  prompt,
  choices,
  correct_answer,
  rationale,
  strategy,
  client_need,
  clinical_judgment,
  status
)
select *
from (values
  ('Medical-Surgical', 'sata', 'A nurse is assessing a patient for dehydration. Which findings are consistent? (Select all that apply)', '[{"id":"a","text":"Decreased skin turgor (tenting over sternum or hand)"},{"id":"b","text":"Urine specific gravity 1.030"},{"id":"c","text":"Bounding peripheral pulses"},{"id":"d","text":"Dry mucous membranes"},{"id":"e","text":"Orthostatic hypotension"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'Dehydration: poor skin turgor, concentrated urine (SG >1.025), dry mucous membranes, orthostatic hypotension (BP drop >20 systolic when standing), weak/thready pulse (not bounding). Bounding pulses indicate fluid overload or high cardiac output states.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a colostomy is concerned because the stoma output is liquid. The nurse assesses that the colostomy is located in the ascending colon. What is the most appropriate response?', '[{"id":"a","text":"\"Liquid output is abnormal — report this to your surgeon.\""},{"id":"b","text":"\"Liquid output is expected from a right-sided (ascending) colostomy because absorption is incomplete.\""},{"id":"c","text":"\"Increase dietary fiber to solidify the stool output.\""},{"id":"d","text":"\"Irrigate the colostomy daily to regulate output.\""}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Colostomy output consistency depends on location: right-sided (ascending) = liquid (less water absorbed), transverse = semi-formed, sigmoid/descending = formed. Liquid output from a right colostomy is expected and normal. Irrigation is only appropriate for sigmoid colostomies.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient takes St. John''s Wort for mild depression and is prescribed indinavir for HIV. What is the nurse''s concern?', '[{"id":"a","text":"St. John''s Wort has no significant drug interactions"},{"id":"b","text":"St. John''s Wort induces CYP3A4, reducing indinavir plasma levels and risk of treatment failure"},{"id":"c","text":"Combining these causes serotonin syndrome"},{"id":"d","text":"St. John''s Wort enhances indinavir causing toxicity"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'St. John''s Wort is a potent CYP3A4 inducer — it increases drug metabolism and reduces plasma levels of many medications including antiretrovirals (indinavir, efavirenz), oral contraceptives, warfarin, and cyclosporine. For HIV medications, this can cause sub-therapeutic levels and treatment failure/resistance.', '', '', '', 'published'),
  ('Leadership and Management', 'sata', 'A nurse is preparing to perform a time-out before a surgical procedure. Which elements are confirmed? (Select all that apply)', '[{"id":"a","text":"Patient identity using two identifiers"},{"id":"b","text":"Correct surgical site marked by the surgeon"},{"id":"c","text":"Procedure to be performed"},{"id":"d","text":"Patient''s insurance coverage"},{"id":"e","text":"Required equipment and implants are available"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Universal Protocol time-out (Joint Commission): correct patient identity, correct procedure, correct surgical site (marked), positioning, required implants/equipment available. All team members must agree before proceeding. Insurance information is administrative and is NOT part of the clinical time-out.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is triaging 4 patients. Which patient has the highest priority?', '[{"id":"a","text":"A 45-year-old with a migraine, vomiting, and pain 8/10"},{"id":"b","text":"A 70-year-old with new onset slurred speech and right-sided arm weakness that started 45 minutes ago"},{"id":"c","text":"A 30-year-old with an ankle sprain, swelling, and pain 5/10"},{"id":"d","text":"A 55-year-old with a chronic back pain exacerbation"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Sudden onset neurological symptoms (slurred speech, unilateral weakness) within 4.5 hours = possible ischemic stroke — time-critical. "Time is brain" — every minute of delay kills neurons. Activate the stroke team immediately. FAST: Face drooping, Arm weakness, Speech difficulty, Time to call. The 30-min window for CT and 60-min window for tPA are benchmarks.', '', '', '', 'published'),
  ('Maternal and Newborn', 'sata', 'A nurse is teaching a pregnant patient about danger signs requiring immediate medical evaluation. Which symptoms are included? (Select all that apply)', '[{"id":"a","text":"Sudden severe headache with visual changes"},{"id":"b","text":"Decreased fetal movement"},{"id":"c","text":"Vaginal bleeding at any gestational age"},{"id":"d","text":"Mild ankle swelling at 36 weeks"},{"id":"e","text":"Severe upper right quadrant pain"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Obstetric danger signs: severe headache + visual changes (preeclampsia/eclampsia), decreased fetal movement (possible fetal distress), any vaginal bleeding, RUQ pain (HELLP syndrome/hepatic capsule distension). Mild ankle edema at 36 weeks is normal. "HELLP": Hemolysis, Elevated Liver enzymes, Low Platelets.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A nurse is performing a pain assessment on a 3-year-old who cannot verbalize pain. Which scale is most appropriate?', '[{"id":"a","text":"Numeric Rating Scale (0–10)"},{"id":"b","text":"FLACC scale (Face, Legs, Activity, Cry, Consolability)"},{"id":"c","text":"Visual Analog Scale"},{"id":"d","text":"McGill Pain Questionnaire"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'FLACC is a behavioral pain assessment tool validated for non-verbal children 2 months–7 years. It scores 5 behavioral indicators (0–2 each, total 0–10). Numeric scales require verbal/cognitive ability (appropriate for ≥6–8 years). The Wong-Baker FACES scale is appropriate for ≥3 years who can point to a face.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient receives tissue plasminogen activator (tPA) for DVT. Which finding 1 hour later requires immediate provider notification?', '[{"id":"a","text":"A mild headache rated 2/10"},{"id":"b","text":"Blood oozing from IV sites"},{"id":"c","text":"Sudden confusion and left-sided arm weakness"},{"id":"d","text":"Temperature increase of 0.5°C"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'New neurological deficits (confusion, focal weakness) after thrombolytic therapy (tPA) = intracranial hemorrhage until proven otherwise — a life-threatening emergency. Stop the tPA infusion immediately and notify the provider. Order emergent CT scan. IV site oozing is expected and managed with pressure.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient on continuous cardiac monitoring develops a rhythm with no discernible P waves, an irregularly irregular pattern, and a ventricular rate of 110 bpm. The nurse identifies this as:', '[{"id":"a","text":"Atrial flutter with 2:1 conduction"},{"id":"b","text":"Atrial fibrillation with rapid ventricular response"},{"id":"c","text":"Third-degree (complete) heart block"},{"id":"d","text":"Ventricular tachycardia"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Atrial fibrillation: chaotic atrial activity (no true P waves, "fibrillatory baseline"), irregularly irregular R-R intervals, variable ventricular rate. A-fib with RVR (rate >100) requires rate control (beta-blockers, calcium channel blockers, digoxin). Anticoagulation is needed for stroke prevention.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A patient requires wound irrigation with a large volume of saline. Which equipment provides the most effective irrigation pressure to remove debris?', '[{"id":"a","text":"Gentle pour from a saline bottle"},{"id":"b","text":"Bulb syringe irrigation"},{"id":"c","text":"35 mL syringe with a 19-gauge angiocath at 8–12 psi"},{"id":"d","text":"Whirlpool hydrotherapy"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Effective wound irrigation requires 8–12 psi to remove bacteria and debris without damaging tissue. A 35 mL syringe with a 19-gauge angiocath delivers approximately 8–10 psi. Bulb syringes deliver <1 psi (inadequate). High-pressure devices (>15 psi) can drive bacteria into tissue.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse is caring for a patient with Type 1 DM admitted for hypoglycemia unawareness. Which teaching points are essential for discharge? (Select all that apply)', '[{"id":"a","text":"Check blood glucose more frequently, especially before driving"},{"id":"b","text":"Keep fast-acting glucose sources available at all times"},{"id":"c","text":"Wear or carry medical ID indicating diabetic status"},{"id":"d","text":"Eat only when blood glucose is above 180 mg/dL"},{"id":"e","text":"Teach family members how to administer glucagon"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Hypoglycemia unawareness (absent warning symptoms): frequent glucose monitoring (CGM strongly recommended), always carry glucose (15g fast carbs), medical ID for emergencies, family glucagon training for severe episodes. Eating only when glucose >180 encourages chronic hyperglycemia — incorrect. Target pre-meal glucose per provider plan.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with dementia becomes agitated and combative every evening (sundowning). Which nursing intervention is most effective?', '[{"id":"a","text":"Administer haloperidol routinely at 1600 hours to prevent agitation"},{"id":"b","text":"Restrain the patient during evening hours for safety"},{"id":"c","text":"Increase meaningful activity in the afternoon and ensure adequate lighting in the evening"},{"id":"d","text":"Move the patient to a quiet room with no stimulation"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Sundowning management: non-pharmacological first. Meaningful daytime activity (prevents boredom and sleep during day), adequate evening lighting (reduces shadows that trigger confusion), consistent routine, calming music, caregiver presence. Routine antipsychotics increase fall risk and are not first-line. Restraints worsen agitation.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 2-year-old child is seen for a well-child visit. The nurse notes the child says 50 words and uses 2-word phrases. What is the nurse''s assessment?', '[{"id":"a","text":"Delayed — refer for speech evaluation immediately"},{"id":"b","text":"Advanced — most 2-year-olds say fewer words"},{"id":"c","text":"Within normal limits — 50+ words and 2-word combinations are expected at age 2"},{"id":"d","text":"Slightly delayed — typical 2-year-olds use only 10–15 words"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Expected language development at 24 months: vocabulary of ≥50 words, 2-word phrases ("more milk"), and beginning of short sentences. Red flags at 2 years: <50 words, no 2-word phrases, loss of previously acquired language (regression). This child''s development is appropriate.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse is discharging a patient who speaks limited English. The patient''s adult child offers to interpret. What is the most appropriate action?', '[{"id":"a","text":"Allow the family member to interpret — it is more comfortable for the patient"},{"id":"b","text":"Use a professional medical interpreter (in-person, video, or phone)"},{"id":"c","text":"Speak slowly and use gestures to convey information"},{"id":"d","text":"Provide only written discharge instructions in English"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Federal law (Title VI, Civil Rights Act) requires healthcare facilities receiving federal funding to provide meaningful access to language services. Family interpreters risk inaccuracy, omission, and HIPAA violations. A certified medical interpreter ensures accuracy and maintains confidentiality. Ask the patient if they prefer a professional interpreter.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient with bipolar disorder taking lithium has the following levels on two consecutive days: 1.8 mEq/L and 2.3 mEq/L. The patient has coarse tremors and is confused. What is the priority action?', '[{"id":"a","text":"Administer the next lithium dose and recheck levels in 12 hours"},{"id":"b","text":"Hold lithium, notify provider, prepare for IV hydration and monitoring"},{"id":"c","text":"Administer activated charcoal for detoxification"},{"id":"d","text":"Increase fluid intake to 2 L orally and recheck level tomorrow"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Lithium toxicity: level 2.3 mEq/L with coarse tremor and confusion = severe toxicity (>2.0 mEq/L). Immediately: HOLD lithium, notify provider, IV saline (promotes renal lithium excretion), monitor neurological status, cardiac rhythm. Severe cases require hemodialysis. There is NO specific antidote for lithium.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with heart failure has jugular venous distension (JVD), 3+ pitting edema, and bilateral crackles. Which position is most therapeutic?', '[{"id":"a","text":"Flat supine to maximize preload"},{"id":"b","text":"Trendelenburg to increase venous return"},{"id":"c","text":"High Fowler''s (90 degrees) with legs dependent"},{"id":"d","text":"Left lateral with head of bed elevated 15 degrees"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'High Fowler''s with legs dependent (dangling): reduces preload (fluid shifts from central to peripheral circulation), decreases pulmonary congestion, improves diaphragmatic excursion and breathing. Supine and Trendelenburg increase venous return (increase preload) — contraindicated in fluid overload. This is the first-line non-pharmacologic intervention for acute decompensated heart failure.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse is assessing a 2-hour-old newborn. Which finding requires immediate intervention?', '[{"id":"a","text":"Respiratory rate of 48 breaths per minute"},{"id":"b","text":"Acrocyanosis (blue hands and feet)"},{"id":"c","text":"Central cyanosis (blue lips and trunk)"},{"id":"d","text":"Molding of the skull from vaginal delivery"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Central cyanosis (lips, tongue, trunk) in a newborn indicates systemic hypoxia — possible congenital heart defect, respiratory distress, or sepsis. This is NEVER normal and requires immediate assessment and intervention. Acrocyanosis (peripheral) is normal in the first 24–48 hours. RR 40–60 and molding are normal newborn findings.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is administering a blood transfusion. Which action is most important to ensure patient safety?', '[{"id":"a","text":"Prime the tubing with dextrose solution before connecting blood"},{"id":"b","text":"Verify blood product with another licensed nurse using two patient identifiers and blood bank information"},{"id":"c","text":"Administer the entire unit as quickly as possible to prevent bacterial growth"},{"id":"d","text":"Start the transfusion and return to check in 2 hours"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Blood transfusion safety: two licensed nurses verify the blood product at the bedside — patient name, DOB, MRN, blood type, expiration date, and unit number match between the patient, wristband, and blood bank label. Fatal hemolytic transfusion reactions occur from wrong-patient errors. Use only 0.9% NS (never dextrose — causes hemolysis).', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is reviewing morning labs for a patient on day 3 of broad-spectrum antibiotics: WBC 24,000, temperature 39.4°C, new onset diarrhea (5–6 loose stools), crampy abdominal pain. Which pathogen is most likely responsible?', '[{"id":"a","text":"Staphylococcus aureus (MRSA)"},{"id":"b","text":"Clostridioides difficile (C. diff)"},{"id":"c","text":"Pseudomonas aeruginosa"},{"id":"d","text":"Candida albicans"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'C. difficile colitis: antibiotic use (disrupts normal flora), new-onset diarrhea (≥3 loose stools/day), crampy pain, leukocytosis, fever. Contact precautions immediately. Diagnosis: C. diff toxin assay. Treatment: oral vancomycin or fidaxomicin. Metronidazole is second-line. ALWAYS wash hands with soap and water (alcohol-based sanitizer does not kill C. diff spores).', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is caring for a patient taking warfarin. Which substances significantly increase the anticoagulant effect and bleeding risk? (Select all that apply)', '[{"id":"a","text":"Aspirin"},{"id":"b","text":"Cranberry juice in large amounts"},{"id":"c","text":"Vitamin K-rich foods (kale, spinach)"},{"id":"d","text":"Fluconazole (antifungal)"},{"id":"e","text":"Rifampin (antibiotic)"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Warfarin interactions: aspirin (adds antiplatelet effect), cranberry juice (inhibits CYP2C9, increases warfarin), fluconazole (inhibits CYP2C9, significantly increases INR). Vitamin K-rich foods DECREASE anticoagulant effect. Rifampin INDUCES CYP enzymes, DECREASING warfarin effect. Consistency of Vit K intake is key — not elimination.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with acute gout asks why they should increase fluid intake. The nurse explains:', '[{"id":"a","text":"Fluid dilutes uric acid in the blood and promotes renal excretion"},{"id":"b","text":"Fluids increase uric acid production to stimulate excretion"},{"id":"c","text":"Dehydration has no effect on gout attacks"},{"id":"d","text":"Fluid intake prevents the need for allopurinol"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Gout results from hyperuricemia and urate crystal deposition in joints. Increased fluid intake (2–3 L/day) dilutes uric acid and promotes renal excretion, reducing serum urate levels. Also avoid: purine-rich foods (organ meats, shellfish), alcohol (especially beer), and dehydration. Colchicine is for acute attacks; allopurinol for prevention.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse is floated to a unit outside their usual practice area. Which action best protects patient safety?', '[{"id":"a","text":"Accept any patient assignment without question to demonstrate flexibility"},{"id":"b","text":"Communicate competency limitations to the charge nurse and only accept assignments within the nurse''s skill level"},{"id":"c","text":"Refuse the float assignment entirely"},{"id":"d","text":"Handle all assigned patients independently without asking for help to avoid appearing incompetent"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Nurses practice within their scope and competency. When floated, communicate honestly about skill limitations (e.g., "I''m not experienced with PICC line care"). Request appropriate orientation and avoid taking high-acuity patients outside your expertise. This protects patients AND the nurse legally. Silence about incompetence is negligence.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A patient is in active labor and requests an epidural. Before administering the epidural, the nurse should:', '[{"id":"a","text":"Obtain verbal consent only since it is an emergency"},{"id":"b","text":"Pre-hydrate with IV fluids, verify platelet count, and obtain informed consent"},{"id":"c","text":"Administer the epidural immediately to reduce maternal stress"},{"id":"d","text":"Check fetal station — epidurals are contraindicated before 8 cm dilation"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Pre-epidural: IV fluid bolus (reduces hypotension risk — common side effect), informed consent, platelet count >80,000 (thrombocytopenia contraindication), baseline FHR documentation. Epidurals are NOT contraindicated at any cervical dilation — this is a common misconception. Maternal hypotension post-epidural → fetal bradycardia; left lateral positioning helps.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is caring for a patient post-kidney transplant on day 5. Labs show: creatinine 3.8 (up from 1.2 yesterday), decreased urine output, weight gain of 2 kg, and the patient reports tenderness over the graft site. Which complication is most likely?', '[{"id":"a","text":"Acute rejection of the transplanted kidney"},{"id":"b","text":"Calcineurin inhibitor nephrotoxicity"},{"id":"c","text":"Urinary tract infection"},{"id":"d","text":"Fluid overload from IV therapy"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Acute rejection (days to months post-transplant): rising creatinine, decreased urine output, weight gain (fluid retention), fever, hypertension, and graft site tenderness. Treatment: high-dose IV corticosteroids, anti-thymocyte globulin. Calcineurin inhibitor toxicity causes gradual rising creatinine without graft tenderness. Notify provider immediately — early treatment preserves the graft.', '', '', '', 'published'),
  ('NGN Case Studies', 'highlight', 'A nurse reviews the following nursing note for a 72-year-old client admitted for a right hip replacement performed this morning. Highlight all findings that require immediate follow-up.', '[]'::jsonb, '{"ids":[]}'::jsonb, 'Immediate follow-up required: SpO₂ 88% on room air (below acceptable threshold, risk of hypoxia), urine output of 15 mL/hr for 3 hours (oliguria, less than 0.5 mL/kg/hr — indicates hypovolemia or AKI), and right calf pain and warmth (classic signs of DVT, a major post-op complication of hip replacement). Temperature 38.1°C and mild incision oozing are expected within first 24 hours post-op and require monitoring, not immediate intervention. HR 88 is within normal limits for a post-op client.', '', '', '', 'published'),
  ('Cardiovascular', 'mcq', 'A client admitted with an acute MI has BP 88/50 mmHg, HR 118 bpm, cool clammy skin, and urine output 15 mL/hr. Which complication does the nurse suspect?', '[{"id":"a","text":"Hypertensive urgency"},{"id":"b","text":"Cardiogenic shock"},{"id":"c","text":"Pulmonary embolism"},{"id":"d","text":"Pericardial tamponade"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Cardiogenic shock: post-MI hypotension + tachycardia + cool/clammy skin + oliguria = the heart cannot pump. Tamponade = Beck''s triad (JVD, muffled sounds, hypotension). PE = pleuritic chest pain + hypoxia.', 'Triad after MI: hypotension + tachy + cold/clammy + low urine = cardiogenic shock. The pump has failed. Peripheral circulation shuts down to preserve core organs.', '', '', 'published'),
  ('Cardiovascular', 'sata', 'A client has left-sided heart failure. Which assessment findings does the nurse expect? Select all that apply.', '[{"id":"a","text":"Bilateral crackles in the lung bases"},{"id":"b","text":"Jugular venous distension"},{"id":"c","text":"Pink frothy sputum"},{"id":"d","text":"Dependent pitting ankle edema"},{"id":"e","text":"S3 gallop heart sound"}]'::jsonb, '{"ids":["a","c","e"]}'::jsonb, 'Left HF backs up into the lungs: crackles, pink frothy sputum (severe pulmonary edema), S3 gallop. JVD and peripheral edema = right HF (backs up into systemic circulation).', 'Left = Lungs. Right = Rest of body. Apply this spatial rule instantly. Left HF = pulmonary. Right HF = peripheral/systemic.', '', '', 'published'),
  ('Cardiovascular', 'mcq', 'A client on IV heparin for DVT has an aPTT of 120 seconds. What is the nurse''s priority action?', '[{"id":"a","text":"Increase the infusion rate"},{"id":"b","text":"Administer protamine sulfate"},{"id":"c","text":"Contact the provider to adjust the rate"},{"id":"d","text":"Repeat the aPTT in 2 hours without changes"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Therapeutic aPTT: 60–100 seconds. At 120 the client is supratherapeutic — high bleeding risk. Notify the provider. Protamine reverses heparin but needs an order. Never independently adjust an infusion.', 'Therapeutic aPTT = 1.5–2.5x normal = 60–100 sec. Above 100 = too much heparin → notify provider. Never adjust an IV infusion without an order.', '', '', 'published'),
  ('Respiratory', 'mcq', 'A client with COPD has ABG: pH 7.32, PaCO₂ 58 mmHg, HCO₃ 28 mEq/L. The nurse interprets this as:', '[{"id":"a","text":"Respiratory alkalosis with metabolic compensation"},{"id":"b","text":"Metabolic acidosis, uncompensated"},{"id":"c","text":"Respiratory acidosis with partial metabolic compensation"},{"id":"d","text":"Mixed respiratory and metabolic alkalosis"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'pH 7.32 = acidosis. PaCO₂ 58 = elevated → respiratory cause. HCO₃ 28 = elevated → kidneys compensating. pH still abnormal = partial compensation. Classic COPD CO₂ retention.', 'ROME: Respiratory Opposite — pH low + PaCO₂ high = respiratory acidosis. Then HCO₃ elevated = kidney compensation. pH still abnormal = partial.', '', '', 'published'),
  ('Respiratory', 'sata', 'A client is placed on airborne precautions. Which actions does the nurse take? Select all that apply.', '[{"id":"a","text":"Place the client in a negative pressure room"},{"id":"b","text":"Wear a surgical mask when entering"},{"id":"c","text":"Wear an N95 respirator before entering"},{"id":"d","text":"Keep the client door closed at all times"},{"id":"e","text":"Client wears a surgical mask during transport"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'Airborne (TB, measles, varicella): negative pressure room, door closed, N95 for staff (NOT surgical mask), client wears surgical mask during transport.', 'Airborne = N95 + negative pressure room. Surgical mask wrong-answer trap: it is used for DROPLET, not airborne. N95 filters tiny airborne particles — surgical masks do not.', '', '', 'published'),
  ('Respiratory', 'mcq', 'A client 30 minutes post-thoracentesis reports sudden sharp chest pain and dyspnea. Breath sounds are absent on the right. The nurse''s first action is to:', '[{"id":"a","text":"Administer the prescribed analgesic"},{"id":"b","text":"Position the client on the affected side"},{"id":"c","text":"Notify the provider immediately"},{"id":"d","text":"Encourage slow deep breathing"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Absent breath sounds + chest pain + dyspnea after thoracentesis = pneumothorax. Life-threatening complication. Notify the provider immediately for chest tube.', 'Post-thoracic procedure + absent breath sounds + dyspnea = pneumothorax until proven otherwise. Always notify provider first — this is an emergency.', '', '', 'published'),
  ('Renal and Urinary', 'mcq', 'A client with CKD has K⁺ 6.4 mEq/L and peaked T waves on the monitor. The nurse implements which intervention first?', '[{"id":"a","text":"Restrict dietary potassium"},{"id":"b","text":"Administer sodium polystyrene sulfonate orally"},{"id":"c","text":"Administer IV calcium gluconate as prescribed"},{"id":"d","text":"Prepare the client for hemodialysis"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Hyperkalemia with cardiac changes needs immediate cardiac membrane stabilization. IV calcium gluconate acts within minutes. Kayexalate removes K⁺ slowly (hours). Dialysis is definitive but not the immediate first step.', 'Hyperkalemia + cardiac changes = cardiac emergency. Stabilize the heart first with calcium gluconate, THEN remove potassium. Stabilize → eliminate.', '', '', 'published'),
  ('Renal and Urinary', 'sata', 'A client is 2 days post-kidney transplant. Which findings require the nurse to notify the provider? Select all that apply.', '[{"id":"a","text":"Urine output 200 mL/hr"},{"id":"b","text":"Creatinine rising from 1.1 to 3.4 mg/dL"},{"id":"c","text":"Temperature 37.2°C (99°F)"},{"id":"d","text":"Graft site tenderness and swelling"},{"id":"e","text":"WBC 11,000/mm³ on tacrolimus"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Polyuria, rising creatinine, and graft tenderness signal acute rejection or ATN. Low-grade fever is expected post-op. Mild WBC elevation on immunosuppressants is expected.', 'Post-transplant "3 Cs": Creatinine rising, Clinical graft changes, output Changes (high or low). Any = notify provider. Low-grade fever and mild WBC elevation = expected.', '', '', 'published'),
  ('Endocrine', 'mcq', 'A client with type 1 diabetes is unresponsive with BG 38 mg/dL. An IV is in place. The nurse''s priority intervention is:', '[{"id":"a","text":"Give 4 oz of orange juice orally"},{"id":"b","text":"Administer 50 mL of 50% dextrose IV"},{"id":"c","text":"Administer glucagon 1 mg IM"},{"id":"d","text":"Recheck BG in 15 minutes"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Unresponsive + IV access + severe hypoglycemia = D50W IV (works in 1–3 min). Oral juice is contraindicated when unconscious — aspiration risk. Glucagon IM only when no IV access available.', 'Unresponsive + IV = D50W first. Conscious + no IV = oral glucose. No IV access at all = glucagon IM. IV route is always fastest in a hypoglycemic emergency.', '', '', 'published'),
  ('Endocrine', 'sata', 'A client is admitted in diabetic ketoacidosis. Which findings does the nurse expect? Select all that apply.', '[{"id":"a","text":"Blood glucose > 300 mg/dL"},{"id":"b","text":"Kussmaul respirations"},{"id":"c","text":"Fruity acetone breath"},{"id":"d","text":"Serum pH of 7.48"},{"id":"e","text":"Positive urine ketones"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'DKA: hyperglycemia, metabolic acidosis (pH < 7.35), ketonuria, Kussmaul respirations (resp compensation), fruity breath. pH 7.48 = alkalosis — contradicts DKA acidosis.', 'DKA = High glucose + Low pH + Ketones + Kussmaul breathing. Eliminate pH 7.48 — DKA causes acidosis (low pH), never alkalosis.', '', '', 'published'),
  ('Endocrine', 'mcq', 'A client is newly prescribed levothyroxine. Which instruction does the nurse provide?', '[{"id":"a","text":"Take with a glass of milk for better absorption"},{"id":"b","text":"Take at bedtime to minimize side effects"},{"id":"c","text":"Take on an empty stomach 30–60 minutes before breakfast"},{"id":"d","text":"Discontinue if you experience palpitations"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Levothyroxine absorption is best on an empty stomach 30–60 min before breakfast. Calcium (milk), antacids, and iron block absorption. Palpitations during titration = contact provider, do not self-discontinue.', 'Empty stomach + morning + 30–60 min before food = best levothyroxine absorption. Calcium and iron block it. Never instruct a client to self-discontinue any medication.', '', '', 'published'),
  ('Gastrointestinal', 'mcq', 'A client 2 days post-colostomy says "I should irrigate my colostomy every day to control output." The nurse recognizes this statement indicates:', '[{"id":"a","text":"Correct understanding of colostomy care"},{"id":"b","text":"A need for further teaching"},{"id":"c","text":"An appropriate long-term goal"},{"id":"d","text":"Standard discharge instruction"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Daily colostomy irrigation is NOT universally required and is not standard teaching. It is an optional technique for sigmoid colostomies. Standard teaching: empty at 1/3–1/2 full, skin care, avoid gas-producing foods.', 'Negative event query: "further teaching" = select the incorrect statement. Daily irrigation is not standard. This is a frequent NCLEX wrong-answer trap — do not confuse irrigation with routine pouch emptying.', '', '', 'published'),
  ('Gastrointestinal', 'sata', 'A client has acute pancreatitis. Which interventions are appropriate? Select all that apply.', '[{"id":"a","text":"Keep the client NPO during the acute phase"},{"id":"b","text":"Administer IV opioid analgesics as prescribed"},{"id":"c","text":"Place the client in high-Fowler''s position"},{"id":"d","text":"Monitor serum amylase and lipase"},{"id":"e","text":"Encourage a high-fat diet to rest the pancreas"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Pancreatitis: NPO (rests pancreas), IV opioids for pain, monitor amylase/lipase. High-fat diet stimulates enzymes — contraindicated. Semi-Fowler''s with knees flexed for comfort, not high-Fowler''s.', 'REST the pancreas: NPO + pain control + monitor markers. High fat = stimulates enzyme secretion = worse. Eliminate both high fat and high-Fowler''s.', '', '', 'published'),
  ('Neurological', 'mcq', 'A client with elevated ICP has BP 182/50 mmHg, HR 44 bpm, and irregular respirations. The nurse recognizes:', '[{"id":"a","text":"Orthostatic hypotension"},{"id":"b","text":"Cushing''s triad"},{"id":"c","text":"Autonomic dysreflexia"},{"id":"d","text":"Neurogenic shock"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Cushing''s triad = late severe ICP sign: hypertension with wide pulse pressure + bradycardia + irregular respirations. Signals impending brain herniation — medical emergency.', 'Cushing''s triad = Hypertension + Bradycardia + Irregular respirations in a neuro client. Wide pulse pressure is the vascular signature. Memorize this cluster — it is the most tested neuro vital sign pattern.', '', '', 'published'),
  ('Neurological', 'mcq', 'A client presents with sudden right-sided weakness, facial droop, and slurred speech with onset 45 minutes ago. The nurse''s priority action is:', '[{"id":"a","text":"Obtain an ECG"},{"id":"b","text":"Keep NPO and notify the stroke team"},{"id":"c","text":"Administer aspirin 325 mg immediately"},{"id":"d","text":"Prepare for cardiac catheterization"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Stroke symptoms within 4.5 hours = tPA window. Activate stroke team and get CT immediately. NPO for swallowing safety. Never give aspirin until CT rules out hemorrhagic stroke — aspirin in hemorrhagic stroke is fatal.', 'FAST within 4.5 hours = stroke team + CT first. No aspirin until hemorrhage is excluded. Time is brain — every minute = 1.9 million neurons lost.', '', '', 'published'),
  ('Neurological', 'sata', 'A client has a tonic-clonic seizure. Which post-ictal nursing actions are appropriate? Select all that apply.', '[{"id":"a","text":"Position the client laterally"},{"id":"b","text":"Insert an oral airway during active seizing"},{"id":"c","text":"Assess for post-ictal confusion and fatigue"},{"id":"d","text":"Document seizure duration and characteristics"},{"id":"e","text":"Restrain the client''s movements"}]'::jsonb, '{"ids":["a","c","d"]}'::jsonb, 'Post-seizure: lateral position (prevents aspiration), assess post-ictal state, document details. Never insert anything into mouth (injury risk). Never restrain (increases injury).', 'Seizure nursing = Protect, Position lateral, Document. Two classic wrong-answer traps: inserting oral airway and restraining. Both cause harm. Nothing goes in the mouth.', '', '', 'published'),
  ('Musculoskeletal', 'mcq', 'A client 6 hours post-hip replacement reports right foot pain, numbness, pallor, and capillary refill of 4 seconds. The nurse''s first action is to:', '[{"id":"a","text":"Elevate the right leg above heart level"},{"id":"b","text":"Apply a warm compress"},{"id":"c","text":"Notify the provider immediately"},{"id":"d","text":"Administer PRN pain medication"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'The 6 Ps post-orthopedic surgery (pain, pallor, paresthesia + prolonged capillary refill) = neurovascular compromise/compartment syndrome. Medical emergency — notify provider immediately. Elevation worsens arterial perfusion.', '6 Ps: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Poikilothermia. Any combination post-orthopedic = notify STAT. Pain medication alone treats the symptom while the limb is dying.', '', '', 'published'),
  ('Fluids and Electrolytes', 'mcq', 'A client receiving IV fluids has Na⁺ 128 mEq/L with headache and confusion. The nurse identifies:', '[{"id":"a","text":"Hypernatremia"},{"id":"b","text":"Hyponatremia"},{"id":"c","text":"Hyperkalemia"},{"id":"d","text":"Hypomagnesemia"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Normal Na⁺ = 135–145 mEq/L. Na⁺ 128 = hyponatremia. Low Na⁺ → water shifts into cells → cerebral edema → neurological symptoms: headache, confusion, nausea, seizures.', '128 < 135 = low sodium = hyponatremia. Low Na⁺ → water into brain cells → brain swells → neuro symptoms. Direct knowledge question — know the normal sodium range.', '', '', 'published'),
  ('Fluids and Electrolytes', 'sata', 'A client has K⁺ 2.8 mEq/L. Which manifestations does the nurse expect? Select all that apply.', '[{"id":"a","text":"Muscle weakness and fatigue"},{"id":"b","text":"Peaked T waves on ECG"},{"id":"c","text":"Hypoactive bowel sounds"},{"id":"d","text":"Flat or inverted T waves on ECG"},{"id":"e","text":"U waves on ECG"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'Hypokalemia (K⁺ < 3.5): muscle weakness, hypoactive bowel/ileus, flat/inverted T waves, U waves. Peaked T waves = HYPERKALEMIA.', 'HyperK = Peaked T waves. HypoK = Flat T + U waves. Peaked T is the wrong-answer trap here — eliminate it.', '', '', 'published'),
  ('Complex Care', 'mcq', 'A nurse has 4 assigned clients. Which client is assessed first?', '[{"id":"a","text":"Client with COPD requesting pain medication for chronic back pain"},{"id":"b","text":"Post-appendectomy day 2 asking for a bedpan"},{"id":"c","text":"Client with chest pain radiating to the left arm and diaphoresis"},{"id":"d","text":"Diabetic client reporting hunger before breakfast"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Chest pain + left arm radiation + diaphoresis = potential MI = life-threatening emergency. The other clients have non-life-threatening, stable needs.', 'Priority = ABC. Ask: "Who could die in the next few minutes?" Chest pain + radiation + diaphoresis = possible MI = first. Apply this decision rule every time.', '', '', 'published')
) as seed(topic, question_type, prompt, choices, correct_answer, rationale, strategy, client_need, clinical_judgment, status)
where not exists (
  select 1
  from public.questions q
  where q.prompt = seed.prompt
);
